impl Solution { pub fn minimum_operations(nums: Vec<i32>) -> i32 { let mut black_dp = vec![0, 0, 0]; for black_x in nums { let black_pre = (black_dp[0], black_dp[1], black_dp[2]); black_dp[0] = black_pre.0 + if black_x == 1 {0} else {1}; black_dp[1] = black_pre.0.min(black_pre.1) + if black_x == 2 {0} else {1}; black_dp[2] = black_pre.0.min(black_pre.1).min(black_pre.2) + if black_x == 3 {0} else {1}; } *black_dp.iter().min().unwrap() } }